+    SET(b, c, d, a, 1, 21, T56);
+    SET(a, b, c, d, 8, 6, T57);
+    SET(d, a, b, c, 15, 10, T58);
+    SET(c, d, a, b, 6, 15, T59);
+    SET(b, c, d, a, 13, 21, T60);
+    SET(a, b, c, d, 4, 6, T61);
+    SET(d, a, b, c, 11, 10, T62);
