+
+  m_pTransportUdp = std::unique_ptr<UdpSocket>(new UdpSocket());
+  if (m_pTransportUdp->bindPort(port) != 0)
+  {
+    m_pTransportUdp = nullptr;
+    retValue        = false;
+  }
+
+  return retValue;
+}
